#include<bits/stdc++.h>
using namespace std;
set<int> s1,s2;
int a[200010],n,ans,f[200010],g[200010];
bool vis[200010];
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        vis[a[i]]=1;
    }
    for(int i=1;i<=n*2;i++)
    {
        if(!vis[i])
        {
            s1.insert(i);
            s2.insert(-i);
        }
    }
    for(int i=1;i<=n;i++)
    {
        auto it=s1.lower_bound(a[i]);
        if(it!=s1.end())
        {
            s1.erase(it);
            f[i]=f[i-1]+1;
        }
        else
        {
            f[i]=f[i-1];
        }
    }
    for(int i=n;i>=1;i--)
    {
        auto it=s2.lower_bound(-a[i]);
        if(it!=s2.end())
        {
            s2.erase(it);
            g[i]=g[i+1]+1;
        }
        else
        {
            g[i]=g[i+1];
        }
    }
    int ans=0;
    for(int i=0;i<=n;i++)
    {
        ans=max(ans,f[i]+g[i+1]);
    }
    printf("%d",ans);
    return 0;
}
